29	/// 64 MiB — leaves headroom for multimodal inputs and OpenAI JSON pass-through bodies,
30	/// well above tonic's 4 MiB decode default.
31	pub const DEFAULT_GRPC_MAX_MESSAGE_SIZE: usize = 64 * 1024 * 1024;
32	
33	/// Resolve the per-message size cap (bytes) applied to the Tonic encoder/decoder.
34	//
35	// TODO(grpc-args): promote SGLANG_TONIC_PAYLOAD to a proper `--grpc-max-message-size`
36	// server argument once the launcher PR (3/4) wires server args through.
37	fn resolve_max_message_size() -> usize {
38	    match std::env::var("SGLANG_TONIC_PAYLOAD") {
39	        Ok(raw) => match raw.parse::<usize>() {
40	            Ok(n) if n > 0 => {
41	                tracing::info!(
42	                    bytes = n,
43	                    "Using SGLANG_TONIC_PAYLOAD override for gRPC max message size"
44	                );
45	                n
46	            }
47	            _ => {
48	                tracing::warn!(
49	                    value = %raw,
50	                    default = DEFAULT_GRPC_MAX_MESSAGE_SIZE,
51	                    "Ignoring invalid SGLANG_TONIC_PAYLOAD; using default"
52	                );
53	                DEFAULT_GRPC_MAX_MESSAGE_SIZE
54	            }
55	        },
56	        Err(_) => DEFAULT_GRPC_MAX_MESSAGE_SIZE,
57	    }
58	}
