60	/// Classify a bridge `PyErr` into the right gRPC `Status`.
61	///
62	/// `PyValueError` / `PyTypeError` mean the client sent bad input — surface as
63	/// `INVALID_ARGUMENT` so callers can distinguish them from server failures.
64	/// Everything else (typically `PyRuntimeError`, but also Python tracebacks
65	/// from inside the tokenizer manager) maps to `INTERNAL`.
66	fn pyerr_to_status(err: PyErr, context: &str) -> Status {
67	    let is_client_error = Python::with_gil(|py| {
68	        err.is_instance_of::<PyValueError>(py) || err.is_instance_of::<PyTypeError>(py)
69	    });
70	    let msg = format!("{}: {}", context, err);
71	    if is_client_error {
72	        Status::invalid_argument(msg)
73	    } else {
74	        Status::internal(msg)
75	    }
76	}
