78	async fn recv_chunk_with_timeout(
79	    receiver: &mut Receiver<ResponseChunk>,
80	    response_timeout: Duration,
81	    timeout_message: impl FnOnce() -> String,
82	) -> Result<Option<ResponseChunk>, Status> {
83	    timeout(response_timeout, receiver.recv())
84	        .await
85	        .map_err(|_| Status::deadline_exceeded(timeout_message()))
86	}
