141	async fn recv_terminal_chunk_for_request(
142	    bridge: &Arc<PyBridge>,
143	    rid: &str,
144	    receiver: &mut Receiver<ResponseChunk>,
145	    response_timeout: Duration,
146	) -> Result<ResponseChunk, Status> {
147	    let mut abort_guard = RequestAbortGuard::new(bridge.clone(), rid.to_string());
148	
149	    match recv_chunk_with_timeout(receiver, response_timeout, || {
150	        format!("Request timed out after {}s", response_timeout.as_secs())
151	    })
152	    .await
153	    {
154	        Ok(Some(ResponseChunk::Data(_))) => {
155	            tracing::warn!(
156	                rid,
157	                "Unary gRPC response received non-terminal Data chunk; expected Finished"
158	            );
159	            abort_guard.abort_now();
160	            Err(Status::internal(
161	                "Unary response protocol violation: expected Finished, got Data",
162	            ))
163	        }
164	        Ok(Some(chunk @ (ResponseChunk::Finished(_) | ResponseChunk::Error(_)))) => {
165	            abort_guard.disarm();
166	            Ok(chunk)
167	        }
168	        Ok(None) => {
169	            let (status, should_abort) = closed_stream_status(bridge, rid);
170	            if should_abort {
171	                abort_guard.abort_now();
172	            } else {
173	                abort_guard.disarm();
174	            }
175	            Err(status)
176	        }
177	        Err(status) => {
178	            if status.code() == tonic::Code::DeadlineExceeded {
179	                abort_guard.abort_now();
180	            } else {
181	                abort_guard.disarm();
182	            }
183	            Err(status)
184	        }
185	    }
186	}
187	
188	fn closed_stream_status(bridge: &Arc<PyBridge>, rid: &str) -> (Status, bool) {
189	    if let Some(error) = bridge.take_terminal_error(rid) {
190	        (terminal_error_status(error), false)
191	    } else {
192	        (
193	            Status::internal("gRPC response stream closed before a terminal response"),
194	            true,
195	        )
196	    }
197	}
198	
199	fn terminal_error_status(error: TerminalError) -> Status {
200	    let message = error.message();
201	    match error {
202	        TerminalError::ChannelFull { .. } => Status::resource_exhausted(message),
203	        TerminalError::ClientDisconnected { .. } | TerminalError::Aborted { .. } => {
204	            Status::cancelled(message)
205	        }
206	    }
207	}
