222	    async fn text_generate(
223	        &self,
224	        request: Request<proto::TextGenerateRequest>,
225	    ) -> Result<Response<Self::TextGenerateStream>, Status> {
226	        let req = request.into_inner();
227	        let rid = req
228	            .rid
229	            .clone()
230	            .unwrap_or_else(|| uuid::Uuid::new_v4().to_string());
231	        let req_dict = build_text_generate_dict(&rid, &req);
232	
233	        let mut receiver = self
234	            .bridge
235	            .submit_request(&rid, "generate", req_dict)
236	            .map_err(|e| pyerr_to_status(e, "Failed to submit request"))?;
237	
238	        let bridge = self.bridge.clone();
239	        let rid_clone = rid.clone();
240	        let response_timeout = self.response_timeout;
241	
242	        let stream = async_stream::stream! {
243	            let mut abort_guard = RequestAbortGuard::new(bridge.clone(), rid_clone.clone());
244	            loop {
245	                match recv_chunk_with_timeout(&mut receiver, response_timeout, || "Stream chunk timed out".to_string()).await {
246	                    Ok(Some(ResponseChunk::Data(data))) => {
247	                        yield Ok(proto::TextGenerateResponse {
248	                            text: data.text.unwrap_or_default(),
249	                            meta_info: data.meta_info,
250	                            finished: false,
251	                        });
252	                    }
253	                    Ok(Some(ResponseChunk::Finished(data))) => {
254	                        abort_guard.disarm();
255	                        yield Ok(proto::TextGenerateResponse {
256	                            text: data.text.unwrap_or_default(),
257	                            meta_info: data.meta_info,
258	                            finished: true,
259	                        });
260	                        break;
261	                    }
262	                    Ok(Some(ResponseChunk::Error(msg))) => {
263	                        abort_guard.disarm();
264	                        yield Err(Status::internal(msg));
265	                        break;
266	                    }
267	                    Ok(None) => {
268	                        let (status, should_abort) = closed_stream_status(&bridge, &rid_clone);
269	                        if should_abort {
270	                            abort_guard.abort_now();
271	                        } else {
272	                            abort_guard.disarm();
273	                        }
274	                        yield Err(status);
275	                        break;
276	                    }
277	                    Err(status) => {
278	                        abort_guard.abort_now();
279	                        yield Err(status);
280	                        break;
281	                    }
282	                }
283	            }
284	        };
285	
286	        Ok(Response::new(Box::pin(stream)))
287	    }
