522	    async fn detokenize(
523	        &self,
524	        request: Request<proto::DetokenizeRequest>,
525	    ) -> Result<Response<proto::DetokenizeResponse>, Status> {
526	        let req = request.into_inner();
527	        if req.tokens.iter().any(|&token| token < 0) {
528	            return Err(Status::invalid_argument(
529	                "Detokenize tokens must be non-negative",
530	            ));
531	        }
532	
533	        // Try Rust-native tokenizer first (no GIL)
534	        if let Some(tok) = self.bridge.rust_tokenizer() {
535	            let ids: Vec<u32> = req.tokens.iter().map(|&t| t as u32).collect();
536	            let text = tok.decode(&ids, true).map_err(Status::internal)?;
537	            return Ok(Response::new(proto::DetokenizeResponse { text }));
538	        }
539	
540	        // Fallback to Python
541	        let json_str = tokio::task::spawn_blocking({
542	            let bridge = self.bridge.clone();
543	            let tokens = req.tokens;
544	            move || bridge.detokenize_py(tokens)
545	        })
546	        .await
547	        .map_err(|e| Status::internal(format!("Task join error: {}", e)))?
548	        .map_err(|e| pyerr_to_status(e, "Detokenize failed"))?;
549	
550	        let v: serde_json::Value = serde_json::from_str(&json_str)
551	            .map_err(|e| Status::internal(format!("Failed to parse JSON response: {}", e)))?;
552	        Ok(Response::new(proto::DetokenizeResponse {
553	            text: v["text"].as_str().unwrap_or("").to_string(),
554	        }))
555	    }
