607	    async fn list_models(
608	        &self,
609	        _request: Request<proto::ListModelsRequest>,
610	    ) -> Result<Response<proto::ListModelsResponse>, Status> {
611	        let json_str = tokio::task::spawn_blocking({
612	            let bridge = self.bridge.clone();
613	            move || bridge.list_models()
614	        })
615	        .await
616	        .map_err(|e| Status::internal(format!("Task join error: {}", e)))?
617	        .map_err(|e| pyerr_to_status(e, "Failed to list models"))?;
618	
619	        let models_arr: Vec<serde_json::Value> = serde_json::from_str(&json_str)
620	            .map_err(|e| Status::internal(format!("Failed to parse models JSON: {}", e)))?;
621	
622	        let models = models_arr
623	            .iter()
624	            .map(|m| proto::ModelCard {
625	                id: m["id"].as_str().unwrap_or("").to_string(),
626	                root: m["root"].as_str().unwrap_or("").to_string(),
627	                parent: m.get("parent").and_then(|v| v.as_str()).map(String::from),
628	                max_model_len: m
629	                    .get("max_model_len")
