630	    #[pyo3(signature = (chunk, finished=false, error=None))]
631	    fn __call__(
632	        &self,
633	        chunk: &Bound<'_, PyDict>,
634	        finished: bool,
635	        error: Option<String>,
636	    ) -> PyResult<ChunkSendStatus> {
637	        let py = chunk.py();
638	        let state = lock_or_recover(self.state.as_ref(), "state");
639	        let sender = match state.channels.get(&self.rid) {
640	            Some(s) => s.clone(),
641	            None => return Ok(ChunkSendStatus::Closed),
642	        };
643	        drop(state);
644	
645	        if let Some(err_msg) = error {
646	            return try_send_chunk(
647	                py,
648	                &self.rid,
649	                &self.state,
650	                &self.runtime_handle,
651	                &self.tokio_handle,
