697	// JSON chunk callback for OpenAI pass-through RPCs (raw bytes).
698	#[pyclass]
699	struct JsonChunkCallback {
700	    rid: String,
701	    state: BridgeStateRef,
702	    runtime_handle: PyObject,
703	    tokio_handle: Handle,
704	}
