707	impl JsonChunkCallback {
708	    /// Register before producing chunks. If a parked chunk drained before registration,
709	    /// Rust fires `on_ready` immediately so late registration cannot miss the edge.
710	    fn set_on_ready(&self, py: Python<'_>, on_ready: PyObject) -> PyResult<()> {
711	        set_on_ready_for_rid(py, &self.rid, &self.state, on_ready)
712	    }
