719	    fn __call__(
720	        &self,
721	        chunk_bytes: &Bound<'_, pyo3::PyAny>,
722	        finished: bool,
723	        error: Option<String>,
724	        status_code: Option<i32>,
725	    ) -> PyResult<ChunkSendStatus> {
