746	        let bytes_data: Vec<u8> = if let Ok(b) = chunk_bytes.extract::<Vec<u8>>() {
747	            b
748	        } else if let Ok(s) = chunk_bytes.extract::<String>() {
749	            s.into_bytes()
750	        } else {
751	            vec![]
752	        };
753	
754	        let mut meta_info = HashMap::new();
755	        if let Some(code) = status_code {
756	            meta_info.insert("status_code".to_string(), code.to_string());
757	        }
